"from datetime import datetime\nfrom werkzeug.security import generate_password_hash, check_password_hash\nfrom app import db\n\nclass User(db.Model):\n    __tablename__ = 'users'\n    id = db.Column(db.Integer, primary_key=True)\n    username = db.Column(db.String(64), unique=True, nullable=False)\n    password_hash = db.Column(db.String(128), nullable=False)\n\n    def set_password(self, password):\n        self.password_hash = generate_password_hash(password)\n\n    def check_password(self, password):\n        return check_password_hash(self.password_hash, password)\n\nclass Mission(db.Model):\n    __tablename__ = 'missions'\n    id = db.Column(db.Integer, primary_key=True)\n    name = db.Column(db.String(64), unique=True, nullable=False)\n    description = db.Column(db.String(256))\n    target_color = db.Column(db.String(32), default=\"red\")\n\nclass MissionHistory(db.Model):\n    __tablename__ = 'mission_history'\n    id = db.Column(db.Integer, primary_key=True)\n    run_id = db.Column(db.String(64), unique=True, nullable=False)\n    mission_name = db.Column(db.String(64), nullable=False)\n    start_time = db.Column(db.DateTime, default=datetime.utcnow)\n    end_time = db.Column(db.DateTime)\n    status = db.Column(db.String(32), default=\"RUNNING\") # RUNNING, COMPLETED, ABORTED, FAILED\n\nclass RobotLog(db.Model):\n    __tablename__ = 'robot_logs'\n    id = db.Column(db.Integer, primary_key=True)\n    timestamp = db.Column(db.DateTime, default=datetime.utcnow)\n    run_id = db.Column(db.String(64))\n    message = db.Column(db.String(256), nullable=False)\n    log_type = db.Column(db.String(32), default=\"INFO\") # INFO, WARNING, ERROR, ACTION\n"